// ================================================================
// FIELD & OPTION ID MAPS  (do not edit unless ClickUp fields change)
// ================================================================
const FIELD = {
  PLATFORM:     'e65ea02e-ac16-4099-aba0-480dd0797703',
  PILLAR:       '36625633-e36e-4a74-8561-eb8d6f81ee8f',
  TYPE:         '218188b6-eedf-49da-aeeb-43aea15ebce9',
  PUB_DATE:     '474ecc61-98e2-4584-bc75-d1dbfef27f48',
  PUB_TIME:     'f58b6b68-42e0-4933-824e-7fcfeac28847',
  COLLAB:       '321cc3c8-1f37-4227-b520-68ff60f78f00',
  BOOST_BUDGET: '5d48fcb0-a77b-4e1a-9873-3672b1b3f290',
  BOOST_GOAL:   '5ad0b430-c2e3-4f3c-8ad3-b42da2d22cec',
  KEYWORD:      '5811d48f-6b47-447c-9194-a701a8647b6e',
  CHANNEL:      'dc7aef29-5593-4566-89fe-bf35567fcfcf',
};

const PLATFORM_MAP = {
  '9821c3c8-f28b-4df6-b301-8d68bfb3b6f9': 'Instagram',
  '45b74f85-e76b-419d-825e-d3813762692b': 'Facebook',
  '64c4b5c5-288c-446c-a492-a697babd21ff': 'TikTok',
  'e43cb995-8ba2-47f2-95d9-2345aaf6961b': 'X',
  '45d7a2cd-308d-40bb-901a-6728306ade3a': 'Pinterest',
  'd8e57eaa-009d-44bb-b06e-95b487276b64': 'YouTube',
  'f792a626-7925-4756-967b-a89ac8f2d0e5': 'LinkedIn',
  '5da8e059-ffa5-4996-a772-46b7d50ab414': 'Reddit',
};

const PILLAR_MAP = {
  '6f56cf9c-a3ae-425d-b967-0b3aae9bc3f5': 'Humor/Relatability/Entertainment',
  '5c4e9824-22e5-4f72-9fd7-018c5a80edc8': 'Educational',
  '9f10a2a4-9c4e-4bcf-a682-6a0d236d0a8a': 'Social Proof',
};

const TYPE_MAP        = { 0:'Infographic', 1:'Post', 2:'Carrousel', 3:'Story', 4:'Video', 5:'Image' };
const BOOST_GOAL_MAP  = { 0:'Awareness', 1:'Engagement', 2:'Followers', 3:'Website clicks' };

// ================================================================
// HELPERS
// ================================================================
function getFieldVal(task, fieldId) {
  const f = (task.custom_fields || []).find(f => f.id === fieldId);
  return f ? f.value : undefined;
}

function isSocialPost(task) {
  const name = task.name || '';
  if (name.startsWith('Post:') || name.startsWith('IG Story -')) return true;
  // Also accept tasks explicitly set to SOCIAL MEDIA channel (index 1)
  return getFieldVal(task, FIELD.CHANNEL) === 1;
}

function tsToISO(ts) {
  if (!ts) return null;
  return new Date(parseInt(ts)).toISOString().split('T')[0];
}

// ================================================================
// COMBINE PAGES AND MAP
// ================================================================
const page0 = $('ClickUp Tasks P0').first().json.tasks || [];
const page1 = $input.first().json.tasks || [];
const allTasks = [...page0, ...page1];

const pipeline = allTasks
  .filter(t => t.parent === null || t.parent === undefined) // parent tasks only
  .filter(isSocialPost)
  .map(task => {
    const platforms = (getFieldVal(task, FIELD.PLATFORM) || [])
      .map(id => PLATFORM_MAP[id]).filter(Boolean);

    const pillar = (getFieldVal(task, FIELD.PILLAR) || [])
      .map(id => PILLAR_MAP[id]).filter(Boolean);

    const typeIdx = getFieldVal(task, FIELD.TYPE);
    const type = (typeIdx !== null && typeIdx !== undefined) ? (TYPE_MAP[typeIdx] || null) : null;

    const pubDateTs = getFieldVal(task, FIELD.PUB_DATE);
    const pubDate = pubDateTs ? tsToISO(pubDateTs) : tsToISO(task.due_date);

    const collab   = !!(getFieldVal(task, FIELD.COLLAB));
    const boostBudget = parseFloat(getFieldVal(task, FIELD.BOOST_BUDGET) || 0) || 0;
    const boostGoalIdx = getFieldVal(task, FIELD.BOOST_GOAL);
    const boostGoal = (boostGoalIdx !== null && boostGoalIdx !== undefined)
      ? (BOOST_GOAL_MAP[boostGoalIdx] || null) : null;
    const keyword  = getFieldVal(task, FIELD.KEYWORD) || null;
    const status   = (task.status && task.status.status ? task.status.status : '').toLowerCase();

    // Auto-infer for IG Story tasks that may not have fields set
    const finalPlatforms = platforms.length ? platforms
      : task.name.startsWith('IG Story -') ? ['Instagram'] : [];
    const finalType = type || (task.name.startsWith('IG Story -') ? 'Story' : null);

    return {
      id: task.id,
      name: task.name,
      status,
      platforms: finalPlatforms,
      content_pillar: pillar,
      type: finalType,
      publication_date: pubDate,
      publish_time: getFieldVal(task, FIELD.PUB_TIME) || null,
      collaboration: collab,
      boost_budget: boostBudget,
      boost_goal: boostGoal,
      keyword_tag: keyword,
      assignees: (task.assignees || []).map(a => a.username),
      url: task.url,
    };
  });

// Boost totals: spent = published posts with budget, committed = upcoming with budget
const boostSpent = pipeline
  .filter(p => p.status === 'done')
  .reduce((sum, p) => sum + (p.boost_budget || 0), 0);
const boostCommitted = pipeline
  .filter(p => p.status !== 'done' && (p.boost_budget || 0) > 0)
  .reduce((sum, p) => sum + p.boost_budget, 0);

return [{ json: { pipeline, boostSpent, boostCommitted } }];

// Get current file from GitHub (needed for SHA and to preserve manual sections)
const ghFile = $('GitHub GET file').first().json;
const currentSha = ghFile.sha;

// Decode current data.json (GitHub returns base64 with line breaks)
const currentContent = Buffer.from(ghFile.content.replace(/\n/g, ''), 'base64').toString('utf8');
let current = {};
try { current = JSON.parse(currentContent); } catch(e) { current = {}; }

// New pipeline data from Map Tasks node
const mapped = $('Map Tasks').first().json;
const pipeline  = mapped.pipeline || [];
const boostSpent     = mapped.boostSpent || 0;
const boostCommitted = mapped.boostCommitted || 0;

// Build merged data.json — pipeline is overwritten, everything else is preserved
const newData = {
  meta: {
    last_updated: new Date().toISOString(),
    month: new Date().toLocaleDateString('en-US', { month: 'long', year: 'numeric' }),
    generated_by: 'n8n'
  },
  pipeline,
  performance: current.performance || {
    instagram: {}, tiktok: {}, facebook: {}, x: {}, linkedin: {}, youtube: {}
  },
  goals: current.goals || {},
  boost: {
    monthly_budget_usd: (current.goals || {}).monthly_boost_budget_usd || 1100,
    spent_usd: boostSpent,
    committed_usd: boostCommitted,
    posts: pipeline.filter(p => p.boost_budget > 0).map(p => ({
      id: p.id,
      name: p.name,
      platforms: p.platforms,
      boost_budget: p.boost_budget,
      boost_goal: p.boost_goal,
      publication_date: p.publication_date,
      status: p.status,
    })),
  },
  search_demand: current.search_demand || { status: 'pending', keywords: [] },
  competitor_watch: current.competitor_watch || { status: 'pending', competitors: [] },
  brand_reputation: current.brand_reputation || { embed_url: null },
  month_debrief: current.month_debrief || { status: 'pending', content: null, slack_posted: false },
};

// Base64-encode for GitHub API
const newJson    = JSON.stringify(newData, null, 2);
const newContent = Buffer.from(newJson, 'utf8').toString('base64');

return [{ json: { content: newContent, sha: currentSha } }];
